#pragma once

#include "PCH.h"

// ============================================================================
// Havok Type Definitions for Engine Relay
//
// CommonLib only partially maps several Havok behavior types — StateInfo has
// all unk fields, TransitionInfo is opaque, and BehaviorReferenceGenerator
// doesn't exist at all. We define the real memory layouts here, derived from
// HKX2E (Havok's own autogenerated class definitions).
//
// These are used exclusively by the Switchboard to construct behavior graph
// objects in memory. We reinterpret_cast from CommonLib's types where needed.
// ============================================================================

namespace EngineRelay {

    // -----------------------------------------------------------------------
    // hkbBehaviorReferenceGenerator
    // Signature: 0x0fcb5423  Size: 0x58 (88 bytes)
    //
    // Inherits: hkbGenerator (0x48 bytes)
    //   + behaviorName (hkStringPtr)    offset 0x48
    //   + behavior     (void*)          offset 0x50  [SERIALIZE_IGNORED]
    // -----------------------------------------------------------------------

    struct ERBehaviorReferenceGenerator
    {
        // We overlay this on allocated memory. The vtable and base class
        // fields are set by copying from a known good hkbGenerator instance
        // or by zeroing and setting the critical fields manually.

        // --- hkReferencedObject (0x10) ---
        void*         vtable;             // 0x00
        std::uint16_t memSizeAndFlags;    // 0x08
        std::uint16_t referenceCount;     // 0x0A
        std::uint32_t pad0C;             // 0x0C

        // --- hkbBindable (0x30) ---
        void*         variableBindingSet; // 0x10
        // hkArray<hkRefVariant> cachedBindables (0x18..0x27)
        std::uint64_t cachedBindables_data;    // 0x18
        std::int32_t  cachedBindables_size;    // 0x20
        std::int32_t  cachedBindables_capAndFlags; // 0x24
        bool          areBindablesCached;      // 0x28
        std::uint8_t  pad29;                   // 0x29
        std::uint16_t pad2A;                   // 0x2A
        std::uint32_t pad2C;                   // 0x2C

        // --- hkbNode (0x48) ---
        std::uint64_t userData;           // 0x30
        RE::hkStringPtr name;             // 0x38
        std::uint16_t id;                 // 0x40
        std::uint8_t  cloneState;         // 0x42
        std::uint8_t  pad43;              // 0x43
        std::uint32_t pad44;              // 0x44

        // --- hkbBehaviorReferenceGenerator ---
        RE::hkStringPtr behaviorName;     // 0x48
        void*           behavior;         // 0x50  (runtime, serialize-ignored)
    };
    static_assert(sizeof(ERBehaviorReferenceGenerator) == 0x58);

    // -----------------------------------------------------------------------
    // hkbStateMachineTimeInterval
    // Size: 16 bytes
    // -----------------------------------------------------------------------
    struct ERTimeInterval
    {
        std::int32_t enterEventId;    // 0x00  (-1 = none)
        std::int32_t exitEventId;     // 0x04  (-1 = none)
        float        enterTime;       // 0x08
        float        exitTime;        // 0x0C
    };
    static_assert(sizeof(ERTimeInterval) == 0x10);

    // -----------------------------------------------------------------------
    // hkbStateMachineTransitionInfo
    // Signature: 0xcdec8025  Size: 0x48 (72 bytes)
    //
    // This is an inline struct (not hkReferencedObject).
    // -----------------------------------------------------------------------

    /// TransitionInfo flags (int16 bitfield) — values from HKX2E TransitionFlags enum.
    static constexpr std::int16_t kTransFlag_DisableCondition  = 0x0100;  // 256
    static constexpr std::int16_t kTransFlag_IsGlobalWildcard  = 0x0400;  // 1024
    static constexpr std::int16_t kTransFlag_IsLocalWildcard   = 0x0800;  // 2048

    /// Combined flags for a standard wildcard transition.
    /// Matches vanilla root SM wildcards: local wildcard + disable condition.
    /// Note: FLAG_IS_GLOBAL_WILDCARD is NOT used by vanilla root SM wildcards.
    static constexpr std::int16_t kTransFlag_Wildcard =
        kTransFlag_IsLocalWildcard | kTransFlag_DisableCondition;

    struct ERTransitionInfo
    {
        ERTimeInterval triggerInterval;   // 0x00
        ERTimeInterval initiateInterval;  // 0x10
        void*           transition;        // 0x20  (hkbTransitionEffect*)
        void*           condition;         // 0x28  (hkbCondition*)
        std::int32_t    eventId;           // 0x30
        std::int32_t    toStateId;         // 0x34
        std::int32_t    fromNestedStateId; // 0x38
        std::int32_t    toNestedStateId;   // 0x3C
        std::int16_t    priority;          // 0x40
        std::int16_t    flags;             // 0x42
        std::uint32_t   pad44;             // 0x44
    };
    static_assert(sizeof(ERTransitionInfo) == 0x48);

    // -----------------------------------------------------------------------
    // hkbStateMachineTransitionInfoArray
    // Signature: 0xe397b11e  Size: 0x20 (32 bytes)
    //
    // Inherits: hkReferencedObject (0x10)
    //   + transitions (hkArray<TransitionInfo>)  offset 0x10
    // -----------------------------------------------------------------------
    struct ERTransitionInfoArray
    {
        // --- hkReferencedObject ---
        void*           vtable;           // 0x00
        std::uint16_t   memSizeAndFlags;  // 0x08
        std::uint16_t   referenceCount;   // 0x0A
        std::uint32_t   pad0C;            // 0x0C

        // --- transitions array ---
        ERTransitionInfo* transitions_data;         // 0x10
        std::int32_t       transitions_size;         // 0x18
        std::int32_t       transitions_capAndFlags;  // 0x1C
    };
    static_assert(sizeof(ERTransitionInfoArray) == 0x20);

    // -----------------------------------------------------------------------
    // hkbStateMachineStateInfo (real layout)
    // Signature: 0x0ed7f9d0  Size: 0x78 (120 bytes)
    //
    // Inherits: hkbBindable (0x30)
    //   + listeners           hkArray<ptr>                   offset 0x30
    //   + enterNotifyEvents   hkbStateMachineEventPropArray* offset 0x40
    //   + exitNotifyEvents    hkbStateMachineEventPropArray* offset 0x48
    //   + transitions         hkbStateMachineTransitionInfoArray* offset 0x50
    //   + generator           hkbGenerator*                  offset 0x58
    //   + name                hkStringPtr                    offset 0x60
    //   + stateId             int32                          offset 0x68
    //   + probability         float                          offset 0x6C
    //   + enable              bool                           offset 0x70
    //   + pad (7 bytes)                                      offset 0x71
    // -----------------------------------------------------------------------
    struct ERStateInfo
    {
        // --- hkReferencedObject (0x10) ---
        void*         vtable;             // 0x00
        std::uint16_t memSizeAndFlags;    // 0x08
        std::uint16_t referenceCount;     // 0x0A
        std::uint32_t pad0C;              // 0x0C

        // --- hkbBindable (0x30) ---
        void*         variableBindingSet; // 0x10
        std::uint64_t cachedBindables_data;    // 0x18
        std::int32_t  cachedBindables_size;    // 0x20
        std::int32_t  cachedBindables_capAndFlags; // 0x24
        bool          areBindablesCached;      // 0x28
        std::uint8_t  pad29;                   // 0x29
        std::uint16_t pad2A;                   // 0x2A
        std::uint32_t pad2C;                   // 0x2C

        // --- StateInfo fields ---
        // listeners (hkArray<hkbStateListener*>)
        void*         listeners_data;     // 0x30
        std::int32_t  listeners_size;     // 0x38
        std::int32_t  listeners_capAndFlags; // 0x3C

        void*         enterNotifyEvents;  // 0x40
        void*         exitNotifyEvents;   // 0x48
        ERTransitionInfoArray* transitions; // 0x50
        RE::hkbGenerator* generator;      // 0x58
        RE::hkStringPtr   name;           // 0x60
        std::int32_t  stateId;            // 0x68
        float         probability;        // 0x6C
        bool          enable;             // 0x70
        std::uint8_t  pad71;              // 0x71
        std::uint16_t pad72;              // 0x72
        std::uint32_t pad74;              // 0x74
    };
    static_assert(sizeof(ERStateInfo) == 0x78);

    // -----------------------------------------------------------------------
    // BSCyclicBlendTransitionGenerator — first field after hkbNode base
    // Signature: 0x5119eb06
    //
    // Inherits: hkbGenerator (0x48 bytes)
    //   + pBlenderGenerator  (hkbGenerator*)  offset 0x48
    //   (EventToFreezeBlendValue, EventToCrossBlend, floats follow)
    // -----------------------------------------------------------------------
    struct ERCyclicBlendGen
    {
        std::uint8_t      _base[0x48];          // hkbNode
        RE::hkbGenerator* pBlenderGenerator;    // 0x48
    };

    // -----------------------------------------------------------------------
    // hkbModifierGenerator — generator children after hkbNode base
    // Signature: 0x0f792802
    //
    // Inherits: hkbGenerator (0x48 bytes)
    //   + modifier   (hkbModifier*)   offset 0x48
    //   + generator  (hkbGenerator*)  offset 0x50
    // -----------------------------------------------------------------------
    struct ERModifierGen
    {
        std::uint8_t      _base[0x48];   // hkbNode
        void*             modifier;      // 0x48  (hkbModifier*)
        RE::hkbGenerator* generator;     // 0x50
    };

    // -----------------------------------------------------------------------
    // hkbBlenderGenerator — children array after hkbNode base + float fields
    // Signature: 0x22df7147
    //
    // Inherits: hkbGenerator (0x48 bytes), then:
    //   0x48 referencePoseWeightThreshold (float)
    //   0x4C blendParameter              (float)
    //   0x50 minCyclicBlendParameter     (float)
    //   0x54 maxCyclicBlendParameter     (float)
    //   0x58 indexOfSyncMasterChild      (int32)
    //   0x5C flags                       (int32)
    //   0x60 subtractLastChild           (bool) + 7-byte pad
    //   0x68 children.data               (hkbBlenderGeneratorChild**)
    //   0x70 children.size               (int32)
    //   0x74 children.capAndFlags        (int32)
    // -----------------------------------------------------------------------
    struct ERBlenderGen
    {
        std::uint8_t  _base[0x68];           // hkbNode + float fields + bool + pad
        void**        children_data;         // 0x68  (hkbBlenderGeneratorChild**)
        std::int32_t  children_size;         // 0x70
        std::int32_t  children_capAndFlags;   // 0x74
    };

    // -----------------------------------------------------------------------
    // hkbBlenderGeneratorChild — generator pointer after hkbBindable base
    // Signature: 0xe2b384b0
    //
    // Inherits: hkbBindable (0x30 bytes)
    //   + generator          (hkbGenerator*)  offset 0x30
    //   + boneWeights        (void*)          offset 0x38
    //   + weight             (float)          offset 0x40
    //   + worldFromModelWeight (float)        offset 0x44
    // -----------------------------------------------------------------------
    struct ERBlenderGenChild
    {
        std::uint8_t      _base[0x30];   // hkbBindable
        RE::hkbGenerator* generator;     // 0x30
    };

    // -----------------------------------------------------------------------
    // hkbEventInfo
    // This type is only forward-declared in CommonLib. The real layout is:
    //   struct hkbEventInfo { uint32_t flags; };
    // flags=0 means the event is not silent. That's the default.
    // -----------------------------------------------------------------------
    struct EREventInfo
    {
        std::uint32_t flags;  // 0 = normal, 1 = FLAG_SILENT
    };
    static_assert(sizeof(EREventInfo) == 0x04);

    // -----------------------------------------------------------------------
    // hkbRoleAttribute
    // Signature: 0x3eb2e082  Size: 4 bytes
    //   + role  (int16)  offset 0x00  (ROLE_DEFAULT = 0)
    //   + flags (int16)  offset 0x02  (FLAG_NONE = 0)
    // -----------------------------------------------------------------------
    struct ERRoleAttribute
    {
        std::int16_t role;    // 0x00  ROLE_DEFAULT = 0
        std::int16_t flags;   // 0x02  FLAG_NONE = 0
    };
    static_assert(sizeof(ERRoleAttribute) == 0x04);

    // -----------------------------------------------------------------------
    // hkbVariableInfo
    // Signature: 0x9e746ba2  Size: 6 bytes (+ 2 pad in arrays)
    //   + role (hkbRoleAttribute)  offset 0x00
    //   + type (int8)              offset 0x04  (VariableType enum)
    //   + pad  (1 byte)            offset 0x05
    //
    // VariableType:
    //   0 = VARIABLE_TYPE_BOOL
    //   1 = VARIABLE_TYPE_INT8
    //   2 = VARIABLE_TYPE_INT16
    //   3 = VARIABLE_TYPE_INT32
    //   4 = VARIABLE_TYPE_REAL
    //   5 = VARIABLE_TYPE_POINTER
    //   6 = VARIABLE_TYPE_VECTOR3
    //   7 = VARIABLE_TYPE_VECTOR4
    //   8 = VARIABLE_TYPE_QUATERNION
    // -----------------------------------------------------------------------
    struct ERVariableInfo
    {
        ERRoleAttribute role;   // 0x00
        std::int8_t      type;   // 0x04
        std::int8_t      pad05;  // 0x05
    };
    static_assert(sizeof(ERVariableInfo) == 0x06);

    // -----------------------------------------------------------------------
    // hkbVariableValue
    // Signature: 0xb99bd6a  Size: 4 bytes
    // A union-like 4-byte word. For bools: 0/1. For floats: IEEE754 bit
    // pattern reinterpreted as int32. For int32: direct value.
    // -----------------------------------------------------------------------
    struct ERVariableValue
    {
        std::int32_t value;  // 0x00
    };
    static_assert(sizeof(ERVariableValue) == 0x04);

    // -----------------------------------------------------------------------
    // hkbVariableValueSet
    // Signature: 0x27812d8d  Size: 0x40 (64 bytes)
    //
    // Inherits: hkReferencedObject (0x10)
    //   + wordVariableValues    hkArray<hkbVariableValue>     offset 0x10
    //   + quadVariableValues    hkArray<hkVector4>            offset 0x20
    //   + variantVariableValues hkArray<hkReferencedObject*>  offset 0x30
    // -----------------------------------------------------------------------
    struct ERVariableValueSet
    {
        // --- hkReferencedObject ---
        void*           vtable;           // 0x00
        std::uint16_t   memSizeAndFlags;  // 0x08
        std::uint16_t   referenceCount;   // 0x0A
        std::uint32_t   pad0C;            // 0x0C

        // wordVariableValues
        ERVariableValue* wordValues_data;         // 0x10
        std::int32_t      wordValues_size;         // 0x18
        std::int32_t      wordValues_capAndFlags;  // 0x1C

        // quadVariableValues (hkVector4)
        void*           quadValues_data;           // 0x20
        std::int32_t    quadValues_size;           // 0x28
        std::int32_t    quadValues_capAndFlags;    // 0x2C

        // variantVariableValues (hkReferencedObject*)
        void*           variantValues_data;        // 0x30
        std::int32_t    variantValues_size;        // 0x38
        std::int32_t    variantValues_capAndFlags; // 0x3C
    };
    static_assert(sizeof(ERVariableValueSet) == 0x40);

}
